### Phase 3: Chat Agent Integration

#### Step 3.1: Create Suggestion Tool

**New file:** `/Users/marcus/conductor/workspaces/brain/montpellier/app/src/server/chat/tools/create-suggestion.ts`

Follows the exact pattern of `/Users/marcus/conductor/workspaces/brain/montpellier/app/src/server/chat/tools/create-observation.ts`.

```typescript
import { tool } from "ai";
import { RecordId } from "surrealdb";
import { z } from "zod";
import { SUGGESTION_CATEGORIES } from "../../../shared/contracts";
import { createEmbeddingVector } from "../../graph/embeddings";
import { isEntityInWorkspace, parseRecordIdString } from "../../graph/queries";
import { createSuggestion } from "../../suggestion/queries";
import { requireToolContext } from "./helpers";
import type { ChatToolDeps } from "./types";

export function createCreateSuggestionTool(deps: ChatToolDeps) {
  return tool({
    description:
      "Create a suggestion for the user. Use when you identify optimizations, risks, opportunities, conflicts, missing elements, or potential pivots that the user should consider.",
    inputSchema: z.object({
      text: z.string().min(1).describe("The suggestion itself — what you propose"),
      category: z.enum(SUGGESTION_CATEGORIES)
        .describe("optimization: improve existing approach. risk: potential problem to address. opportunity: beneficial possibility. conflict: contradictory elements. missing: gap in current plan. pivot: fundamental direction change."),
      rationale: z.string().min(1).describe("Why you are making this suggestion — the reasoning and evidence"),
      confidence: z.number().min(0).max(1).describe("How confident you are in this suggestion (0-1)"),
      target_entity_id: z.string().optional()
        .describe("Optional target entity this suggestion is about (project/feature/task/question/decision, format: table:id)"),
      evidence_entity_ids: z.array(z.string()).optional()
        .describe("Optional entity IDs that support the rationale (format: table:id)"),
    }),
    execute: async (input, options) => {
      const context = requireToolContext(options);

      // Validate and parse target entity
      type TargetTable = "project" | "feature" | "task" | "question" | "decision";
      const targetTables: TargetTable[] = ["project", "feature", "task", "question", "decision"];
      const targetRecord = input.target_entity_id
        ? parseRecordIdString(input.target_entity_id, targetTables) as RecordId<TargetTable, string>
        : undefined;

      if (targetRecord) {
        const scoped = await isEntityInWorkspace(deps.surreal, context.workspaceRecord, targetRecord);
        if (!scoped) {
          throw new Error("target entity is outside the current workspace scope");
        }
      }

      // Validate and parse evidence entities
      const evidenceTables = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation"] as const;
      const evidenceRecords = input.evidence_entity_ids?.map(id =>
        parseRecordIdString(id, [...evidenceTables])
      );

      // Create embedding
      const embedding = await createEmbeddingVector(deps.embeddingModel, input.text, deps.embeddingDimension);
      if (!embedding) {
        throw new Error("failed to create embedding for create_suggestion");
      }

      const suggestionRecord = await createSuggestion({
        surreal: deps.surreal,
        workspaceRecord: context.workspaceRecord,
        text: input.text,
        category: input.category,
        rationale: input.rationale,
        suggestedBy: context.actor,
        confidence: input.confidence,
        now: new Date(),
        sourceMessageRecord: context.currentMessageRecord,
        ...(targetRecord ? { targetRecord } : {}),
        ...(evidenceRecords ? { evidenceRecords } : {}),
        embedding,
      });

      return {
        suggestion_id: `suggestion:${suggestionRecord.id as string}`,
        category: input.category,
        status: "pending",
      };
    },
  });
}
```

