import { listWorkspacePendingSuggestions } from "../suggestion/queries";
```

2. Add to the parallel data loading (in the `Promise.all` around line 62):
```typescript
const [
  provisionalDecisions,
  conflicts,
  blockingQuestions,
  lowConfidenceDecisions,
  blockedTasks,
  observations,
  suggestions,
  staleTasks,
  recentlyCompleted,
  recentExtractions,
] = await Promise.all([
  // ... existing ...
  listWorkspacePendingSuggestions({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
  // ... existing ...
]);
```

3. Add pending suggestions to the review tier (after the observations loop, around line 200):
```typescript
// Review: pending suggestions from agents
for (const sug of suggestions) {
  review.push({
    id: `suggestion:${sug.id}:${sug.category}`,
    tier: "review",
    entityId: `suggestion:${sug.id}`,
    entityKind: "suggestion",
    entityName: sug.text,
    reason: `${capitalize(sug.category)} suggestion from ${sug.suggestedBy} (confidence ${Math.round(sug.confidence * 100)}%)`,
    status: sug.status,
    createdAt: sug.createdAt,
    actions: suggestionActions(),
  });
}
```

4. Add a `suggestionActions` helper:
```typescript
function suggestionActions(): GovernanceFeedAction[] {
  return [
    { action: "accept", label: "Accept" },
    { action: "defer", label: "Defer" },
    { action: "dismiss", label: "Dismiss" },
    { action: "discuss", label: "Discuss" },
  ];
}
```

---

### Graph Route Update

**File:** `/Users/marcus/conductor/workspaces/brain/montpellier/app/src/server/graph/graph-route.ts`

Add `"suggestion"` to the `entityTables` arrays on lines 45 and 67 (the focused graph view and center entity parsing):
```typescript
const entityTables: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "suggestion"];
```

---

### What Is Deferred

The following are explicitly out of scope for this PR and should be tracked as follow-up items:

1. **Conversion flow** -- the `converted_from` relation table is defined in schema, but the logic to convert a suggestion into a task/feature/decision/project (creating the entity, updating suggestion status to "converted", creating the `converted_from` edge) is deferred.
2. **SSE streaming event** -- no `SuggestionEvent` SSE type. Suggestions are created by agent tools, and tool results already surface in the chat. A dedicated SSE event for real-time suggestion notifications can be added later.
3. **MCP suggestion endpoints** -- no MCP route for creating/listing suggestions from coding agents. Follow the `handleLogObservation` pattern when needed.
4. **Background trigger patterns** -- no periodic or event-driven suggestion generation. Suggestions are created ad-hoc by agents during chat/PM agent execution.
5. **Suggestion in `search_entities` tool** -- suggestions are not added to the `SearchEntityKind` type used by the chat agent's semantic search tool. They are discoverable via BM25 UI search only.

---

### Implementation Order

The dependency chain is:

1. Migration + master schema (independent foundation)
2. contracts.ts types (independent foundation)
3. suggestion/queries.ts (depends on 1 + 2)
4. graph/queries.ts + transform.ts updates (depends on 2)
5. chat/tools/create-suggestion.ts + index.ts (depends on 3 + 4)
6. entity-actions-route.ts (depends on 3)
7. entity-detail-route.ts + entity-search-route.ts (depends on 4)
8. chat/context.ts (depends on 3)
9. agents/pm/tools.ts + prompt.ts (depends on 3 + 5)
10. feed/feed-route.ts (depends on 3)
11. graph/graph-route.ts (depends on 4)

Steps 1-4 can be done in the first pass. Steps 5-11 can be done in parallel in the second pass.

---

### Critical Files for Implementation

- `/Users/marcus/conductor/workspaces/brain/montpellier/app/src/server/observation/queries.ts` - Direct pattern to follow for suggestion/queries.ts (CRUD functions, workspace scoping, listing)
- `/Users/marcus/conductor/workspaces/brain/montpellier/app/src/server/chat/tools/create-observation.ts` - Direct pattern to follow for create-suggestion.ts (tool definition, embedding, relation creation, scope validation)
- `/Users/marcus/conductor/workspaces/brain/montpellier/app/src/shared/contracts.ts` - Core type definitions to extend (EntityKind, action types, summary types)
- `/Users/marcus/conductor/workspaces/brain/montpellier/app/src/server/graph/queries.ts` - Must update GraphEntityTable, readEntityName, isEntityInWorkspace to include suggestion
- `/Users/marcus/conductor/workspaces/brain/montpellier/app/src/server/chat/context.ts` - Chat context loading and system prompt generation to include pending suggestions

