288→// --- Action button builders ---
289→
290→function decisionActions(): GovernanceFeedAction[] {
291→  return [
292→    { action: "confirm", label: "Confirm" },
293→    { action: "override", label: "Override" },
294→    { action: "discuss", label: "Discuss" },
295→  ];
296→}
297→
298→function conflictActions(): GovernanceFeedAction[] {
299→  return [
300→    { action: "acknowledge", label: "Acknowledge" },
301→    { action: "resolve", label: "Resolve" },
302→    { action: "discuss", label: "Discuss" },
303→  ];
304→}
305→
306→function questionActions(): GovernanceFeedAction[] {
307→  return [
308→    { action: "discuss", label: "Answer" },
309→    { action: "dismiss", label: "Dismiss" },
310→  ];
311→}
312→
313→function observationActions(status: string): GovernanceFeedAction[] {
314→  if (status === "acknowledged") {
315→    return [
316→      { action: "resolve", label: "Resolve" },
317→    ];
318→  }
319→  return [
320→    { action: "acknowledge", label: "Acknowledge" },
321→    { action: "resolve", label: "Resolve" },
322→  ];
323→}
324→
325→function blockedTaskActions(): GovernanceFeedAction[] {
326→  return [
327→    { action: "complete", label: "Complete" },
328→    { action: "discuss", label: "Discuss" },
329→  ];
330→}
331→
332→function staleTaskActions(): GovernanceFeedAction[] {
333→  return [
334→    { action: "complete", label: "Complete" },
335→    { action: "discuss", label: "Discuss" },
336→  ];
337→}
338→
339→function capitalize(value: string): string {
340→  if (value.length === 0) return value;
341→  return value.charAt(0).toUpperCase() + value.slice(1);
342→}
