import { RecordId } from "surrealdb";
import type { EntityKind, SearchEntityResponse } from "../../shared/contracts";
import { HttpError } from "../http/errors";
import { elapsedMs, logDebug, logError, logInfo, logWarn } from "../http/observability";
import { jsonError, jsonResponse } from "../http/response";
import type { ServerDependencies } from "../runtime/types";
import { resolveWorkspaceProjectRecord, resolveWorkspaceRecord } from "../workspace/workspace-scope";

type SearchEntityRow = {
  id: RecordId<string, string>;
  kind: EntityKind;
  text: string;
  score: number;
};

// BM25 full-text search queries per entity type.
// Queries run from app layer because:
// 1. search::score() / @N@ don't work inside DEFINE FUNCTION (https://github.com/surrealdb/surrealdb/issues/7013)
// 2. @N@ doesn't work with SDK bound parameters — search term must be a string literal

function escapeSearchQuery(query: string): string {
  return query.replace(/\\/g, "\\\\").replace(/'/g, "\\'");
}

function buildWorkspaceSearchSQL(escapedQuery: string): string {
  const q = `'${escapedQuery}'`;
  return `
SELECT id, "task" AS kind, title AS text, search::score(1) AS score
FROM task WHERE title @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;

SELECT id, "decision" AS kind, summary AS text, search::score(1) AS score
FROM decision WHERE summary @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;

SELECT id, "question" AS kind, text AS text, search::score(1) AS score
FROM question WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;

SELECT id, "observation" AS kind, text AS text, search::score(1) AS score
FROM observation WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;

SELECT id, "feature" AS kind, name AS text, search::score(1) AS score
FROM feature WHERE name @1@ ${q} ORDER BY score DESC LIMIT $limit;

SELECT id, "project" AS kind, name AS text, search::score(1) AS score
FROM project WHERE name @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;

SELECT id, "person" AS kind, name AS text, search::score(1) AS score
FROM person WHERE name @1@ ${q} ORDER BY score DESC LIMIT $limit;

SELECT id, "message" AS kind, text AS text, search::score(1) AS score
FROM message WHERE text @1@ ${q} AND conversation.workspace = $workspace ORDER BY score DESC LIMIT $limit;
`;
}

function buildProjectSearchSQL(escapedQuery: string): string {
  const q = `'${escapedQuery}'`;
  return `
LET $project_entity_ids = SELECT VALUE in FROM belongs_to WHERE out = $project;

SELECT id, "task" AS kind, title AS text, search::score(1) AS score
FROM task WHERE title @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;

SELECT id, "decision" AS kind, summary AS text, search::score(1) AS score
FROM decision WHERE summary @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;

SELECT id, "question" AS kind, text AS text, search::score(1) AS score
FROM question WHERE text @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;

SELECT id, "observation" AS kind, text AS text, search::score(1) AS score
FROM observation WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;

SELECT id, "feature" AS kind, name AS text, search::score(1) AS score
FROM feature WHERE name @1@ ${q} AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;

SELECT id, "message" AS kind, text AS text, search::score(1) AS score
FROM message WHERE text @1@ ${q} AND conversation.workspace = $workspace ORDER BY score DESC LIMIT $limit;
`;
}

export function createEntitySearchHandler(deps: ServerDependencies): (url: URL) => Promise<Response> {
  return (url: URL) => handleEntitySearch(deps, url);
}

async function handleEntitySearch(deps: ServerDependencies, url: URL): Promise<Response> {
  const startedAt = performance.now();
  const workspaceId = url.searchParams.get("workspaceId")?.trim();
  if (!workspaceId) {
    return jsonError("workspaceId is required", 400);
  }

  const projectId = url.searchParams.get("projectId")?.trim();

  const query = url.searchParams.get("q")?.trim();
  if (!query) {
    return jsonError("q is required", 400);
  }

  const rawLimit = url.searchParams.get("limit");
  const parsedLimit = Number(rawLimit ?? "10");
  if (!Number.isFinite(parsedLimit) || parsedLimit < 1) {
    return jsonError("limit must be a positive number", 400);
  }

  const limit = Math.min(Math.floor(parsedLimit), 100);
  logDebug("http.request.validated", "Entity search request validated", {
    workspaceId,
    projectId,
    limit,
    queryLength: query.length,
  });
  logInfo("entity.search.started", "Entity search started", {
    workspaceId,
    projectId,
    limit,
  });

  let workspaceRecord: RecordId<"workspace", string>;
  let projectRecord: RecordId<"project", string> | undefined;

  try {
    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
    if (projectId) {
      projectRecord = await resolveWorkspaceProjectRecord(deps.surreal, workspaceRecord, projectId);
    }
  } catch (error) {
    if (error instanceof HttpError) {
      logWarn("entity.search.http_error", "Entity search failed with client-facing error", {
        workspaceId,
        projectId,
        statusCode: error.status,
      });
      return jsonError(error.message, error.status);
    }

    logError("entity.search.scope_validation.failed", "Entity search scope validation failed", error, {
      workspaceId,
      projectId,
    });
    const errorText = error instanceof Error ? error.message : "failed to validate scope";
    return jsonError(errorText, 500);
  }

  const escaped = escapeSearchQuery(query);
  const sql = projectRecord
    ? buildProjectSearchSQL(escaped)
    : buildWorkspaceSearchSQL(escaped);

  const bindings = {
    limit,
    workspace: workspaceRecord,
    ...(projectRecord ? { project: projectRecord } : {}),
  };

  const results = await deps.surreal.query(sql, bindings);

  const allRows = (results as unknown as SearchEntityRow[][])
    .filter(Array.isArray)
    .flat()
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);

  const responseRows = allRows.map((row) => ({
    id: row.id.id as string,
    kind: row.kind,
    text: row.text,
    confidence: row.score,
    sourceId: "",
    sourceKind: "message",
  } satisfies SearchEntityResponse));

  logInfo("entity.search.completed", "Entity search completed", {
    workspaceId,
    projectId,
    limit,
    resultCount: responseRows.length,
    durationMs: elapsedMs(startedAt),
  });

  return jsonResponse(responseRows, 200);
}

import { RecordId, Surreal } from "surrealdb";
import { listWorkspaceProjectSummaries } from "../../graph/queries";
import { listWorkspaceOpenObservations } from "../../observation/queries";

function formatProjects(rows: Awaited<ReturnType<typeof listWorkspaceProjectSummaries>>): string {
  if (rows.length === 0) {
    return "- none";
  }

  return rows
    .slice(0, 20)
    .map((row) => `- ${row.name} [id: ${row.id}] active tasks: ${row.activeTaskCount}`)
    .join("\n");
}

function formatObservations(rows: Awaited<ReturnType<typeof listWorkspaceOpenObservations>>): string {
  if (rows.length === 0) {
    return "- none";
  }

  return rows
    .slice(0, 20)
    .map((row) => {
      const category = row.category ? `, ${row.category}` : "";
      return `- [${row.severity}] ${row.text} (${row.status}, by ${row.sourceAgent}${category})`;
    })
    .join("\n");
}

export async function buildPmSystemPrompt(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
}): Promise<string> {
  const [projects, observations] = await Promise.all([
    listWorkspaceProjectSummaries({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 20,
    }),
    listWorkspaceOpenObservations({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 20,
    }),
  ]);

  return [
    "You are the Product Manager subagent.",
    "You are the single authority on tasks, features, projects, and project status.",
    "",
    "## Architecture: Graph as Communication Bus",
    "All agent-to-agent communication happens through the knowledge graph.",
    "Never rely on handoff text from other agents; read context from graph tools.",
    "Other agents (Research, Engineering, Marketing, etc.) write to the same graph.",
    "You may discover entities and observations created by other agents when querying.",
    "Your observations are visible to all agents in subsequent invocations.",
    "",
    "## Entity Kind Classification",
    "- Project: named product/system, top-level workstream (proper noun, building/launching language)",
    "- Feature: capability/requirement within a project (supports, provides, enables, needs to handle)",
    "- Task: concrete executable work with action verb (implement, build, fix, migrate, deploy, test)",
    "",
    "## When to Create Directly vs Suggest",
    "- Direct creation (create_work_item): user explicitly says \"add/create/make a task for X\", onboarding entity seeding, clear actionable items",
    "- Suggestions (suggest_work_items): user is discussing/brainstorming, PM agent infers potential work items, low certainty",
    "",
    "## Category Classification (tasks only)",
    "engineering, research, marketing, operations, design, sales.",
    "Classify by what the entity affects, not where it came up.",
    "",
    "## Priority Classification (tasks only)",
    "critical: urgent/ASAP/blocking/P0, high: important/soon/P1, low: nice-to-have/backlog/P3, medium: default.",
    "",
    "## What NOT to Create",
    "- Vague references (\"my project\", \"the feature\")",
    "- Questions-as-features (user asks \"should we do X?\" — that's a question, not a feature)",
    "- Hypotheticals (\"what if we did X?\")",
    "- Descriptive verbs in system overviews (\"the system will ingest, render, process\")",
    "",
    "## Workspace Projects",
    formatProjects(projects),
    "",
    "## Active Observations",
    formatObservations(observations),
    "",
    "## Core Responsibilities",
    "- Task dedup and merge awareness across all agent suggestions.",
    "- Feature and dependency risk tracking (surface blockers via observations).",
    "- Project status aggregation when the user asks for status, progress, or blockers.",
    "- Cross-agent awareness: know what all agents have suggested/created.",
    "",
    "## Task Suggestion Rules",
    "1. Use suggest_work_items for batches of proposed tasks/features/projects with dedup.",
    "2. Exact duplicate of an open/in_progress item: treat as duplicate_found.",
    "3. Similar open/in_progress item with meaningful scope overlap: include possible_duplicate with similarity score.",
    "4. Similar closed/completed item: treat as new scope and keep as suggestion.",
    "5. No meaningful match: keep as new suggestion.",
    "",
    "## Feature Management",
    "- Features decompose into tasks. Track which tasks belong to which feature.",
    "- When all tasks for a feature are completed, note it in the summary.",
    "- Create observations when features are at risk (blocked tasks, missing tasks).",
    "",
    "## Project Status Rules",
    "- When intent is check_status, call get_project_status.",
    "- Include active tasks, blocked tasks, recent decisions, open questions, and active observations.",
    "",
    "## Observation Rules",
    "- Create observations for: cross-agent risks, conflicts, stale blockers, missing execution paths, at-risk features.",
    "- Set severity to conflict for contradictions, warning for risks, info for awareness.",
    "- Other agents will see your observations when they next query the graph.",
    "",
    "## Output",
    "If no suggestions remain after dedup, return suggestions: [].",
  ].join("\n");
}

