 1→import { z } from "zod";
 2→import { ENTITY_CATEGORIES, ENTITY_PRIORITIES } from "../../shared/contracts";
 3→
 4→// Azure structured output requires all properties in `required` — no optional fields allowed.
 5→// Use "none" sentinel in the extraction schema, then strip it to undefined after parsing.
 6→const extractionCategorySchema = z.enum([...ENTITY_CATEGORIES, "none"]).transform(
 7→  (v) => (v === "none" ? undefined : v),
 8→);
 9→
10→const extractionPrioritySchema = z.enum([...ENTITY_PRIORITIES, "none"]).transform(
11→  (v) => (v === "none" ? undefined : v),
12→);
13→
14→const extractionEntityBaseSchema = z.object({
15→  tempId: z.string().min(1),
16→  kind: z.enum(["project", "feature", "task", "decision", "question"]),
17→  text: z.string().min(3).max(200),
18→  confidence: z.number().min(0).max(1),
19→  evidence: z.string().min(1),
20→  category: extractionCategorySchema,
21→  priority: extractionPrioritySchema,
22→}).strict();
23→
24→const extractionEntityWithAssigneeSchema = extractionEntityBaseSchema.extend({
25→  assignee_name: z.string().min(1),
26→}).strict();
27→
28→const extractionEntityWithResolvedFromSchema = extractionEntityBaseSchema.extend({
29→  resolvedFromMessageId: z.string().min(1),
30→}).strict();
31→
32→const extractionEntityWithAssigneeAndResolvedFromSchema = extractionEntityBaseSchema.extend({
33→  assignee_name: z.string().min(1),
34→  resolvedFromMessageId: z.string().min(1),
35→}).strict();
36→
37→const extractionEntitySchema = z.union([
38→  extractionEntityBaseSchema,
39→  extractionEntityWithAssigneeSchema,
40→  extractionEntityWithResolvedFromSchema,
41→  extractionEntityWithAssigneeAndResolvedFromSchema,
42→]);
43→
44→export const extractionRelationshipSchema = z.object({
45→  kind: z.string().min(1),
46→  fromTempId: z.string().min(1),
47→  toTempId: z.string().min(1),
48→  confidence: z.number().min(0).max(1),
49→  fromText: z.string().min(1),
50→  toText: z.string().min(1),
51→}).strict();
52→
53→export const extractionResultSchema = z.object({
54→  entities: z.array(extractionEntitySchema),
55→  relationships: z.array(extractionRelationshipSchema),
56→  tools: z.array(z.string().min(1)),
57→}).strict();
58→
59→export type ExtractionPromptEntity = z.infer<typeof extractionEntitySchema>;
60→export type ExtractionPromptRelationship = z.infer<typeof extractionRelationshipSchema>;
61→export type ExtractionPromptOutput = z.infer<typeof extractionResultSchema>;
62→
63→export function parseExtractionOutput(payload: unknown):
64→  | { ok: true; data: ExtractionPromptOutput }
65→  | { ok: false; error: string } {
66→  const result = extractionResultSchema.safeParse(payload);
67→  if (result.success) {
68→    return { ok: true, data: result.data };
69→  }
70→
71→  return {
72→    ok: false,
73→    error: result.error.issues[0]?.message ?? "Invalid extraction payload",
74→  };
75→}
