260→function buildEntityRecordContent(
261→  kind: PersistableExtractableEntityKind,
262→  text: string,
263→  confidence: number,
264→  now: Date,
265→  workspaceRecord: RecordId<"workspace", string>,
266→  embedding?: number[],
267→  sourceMessageRecord?: RecordId<"message", string>,
268→  sourceCommitRecord?: RecordId<"git_commit", string>,
269→  category?: string,
270→  priority?: string,
271→): Record<string, unknown> {
272→  if (kind === "project") {
