282→
283→  if (kind === "feature") {
284→    return {
285→      name: text,
286→      status: "active",
287→      ...(embedding ? { embedding } : {}),
288→      created_at: now,
289→      updated_at: now,
290→    };
291→  }
292→
293→  if (kind === "task") {
294→    return {
295→      title: text,
296→      status: "open",
297→      extraction_confidence: confidence,
298→      extracted_at: now,
299→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
300→      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
301→      ...(embedding ? { embedding } : {}),
302→      ...(category ? { category } : {}),
303→      ...(priority ? { priority } : {}),
304→      workspace: workspaceRecord,
305→      created_at: now,
306→      updated_at: now,
307→    };
308→  }
309→
310→  if (kind === "decision") {
311→    return {
312→      summary: text,
313→      status: "extracted",
314→      extraction_confidence: confidence,
