436→export function normalizeRelationshipKind(value: string): string {
437→  return value
438→    .trim()
439→    .replace(/[^a-zA-Z0-9]+/g, "_")
440→    .replace(/_+/g, "_")
441→    .replace(/^_/, "")
442→    .replace(/_$/, "")
443→    .toUpperCase();
444→}
