446→function cosineSimilarity(a: number[], b: number[]): number {
447→  if (a.length !== b.length) {
448→    return -1;
449→  }
450→
451→  let dot = 0;
452→  let normA = 0;
453→  let normB = 0;
454→
455→  for (let i = 0; i < a.length; i += 1) {
456→    dot += a[i] * b[i];
457→    normA += a[i] * a[i];
458→    normB += b[i] * b[i];
459→  }
460→
461→  if (normA === 0 || normB === 0) {
462→    return -1;
463→  }
464→
465→  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
466→}
