202→  }
203→
204→  if (kind === "project" || kind === "feature") {
205→    await surreal.update(candidate.id as RecordId<"project" | "feature", string>).merge({
206→      name: incomingText,
207→      updated_at: now,
208→    });
209→    return incomingText;
210→  }
211→
212→  if (kind === "task") {
213→    await surreal.update(candidate.id as RecordId<"task", string>).merge({
214→      title: incomingText,
215→      updated_at: now,
216→    });
217→    return incomingText;
218→  }
219→
220→  if (kind === "decision") {
221→    await surreal.update(candidate.id as RecordId<"decision", string>).merge({
222→      summary: incomingText,
223→      updated_at: now,
224→    });
225→    return incomingText;
226→  }
227→
228→  await surreal.update(candidate.id as RecordId<"question", string>).merge({
229→    text: incomingText,
230→    updated_at: now,
231→  });
232→
233→  return incomingText;
