 34→    ...(input.category ? { category: input.category } : {}),
 35→    ...(input.observationType ? { observation_type: input.observationType } : {}),
 36→    source_agent: input.sourceAgent,
 37→    workspace: input.workspaceRecord,
 38→    ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
 39→    ...(input.sourceSessionRecord ? { source_session: input.sourceSessionRecord } : {}),
 40→    ...(input.embedding ? { embedding: input.embedding } : {}),
 41→    created_at: input.now,
 42→    updated_at: input.now,
 43→  });
 44→
 45→  if (input.relatedRecord) {
 46→    await input.surreal
 47→      .relate(observationRecord, new RecordId("observes", randomUUID()), input.relatedRecord, {
 48→        added_at: input.now,
 49→      })
 50→      .output("after");
 51→  }
 52→
 53→  return observationRecord;
