 27→      rationale: z.string().min(1).describe("Why this entity is needed — seeds the description"),
 28→      category: z.enum(ENTITY_CATEGORIES).optional().describe("Category classification"),
 29→      priority: z.enum(ENTITY_PRIORITIES).optional().describe("critical: blocking/urgent. high: important, needs attention soon. medium: normal priority. low: nice-to-have, deferred."),
 30→      project: z.string().optional().describe("Project name to scope the entity under"),
 31→    }),
 32→    execute: async (input, options) => {
 33→      const context = requireToolContext(options);
 34→      const now = new Date();
 35→
 36→      const embedding = await createEmbeddingVector(
 37→        deps.embeddingModel,
 38→        input.title,
 39→        deps.embeddingDimension,
 40→      );
 41→
 42→      const entityId = randomUUID();
 43→
 44→      if (input.kind === "project") {
 45→        const projectRecord = await createProjectRecord({
 46→          surreal: deps.surreal,
 47→          name: input.title,
 48→          status: "active",
 49→          now,
 50→          workspaceRecord: context.workspaceRecord,
 51→          sourceMessageRecord: context.currentMessageRecord,
 52→        });
 53→
 54→        if (embedding) {
 55→          await deps.surreal.update(projectRecord).merge({ embedding });
 56→        }
 57→
 58→        void seedDescriptionEntry({
 59→          surreal: deps.surreal,
 60→          targetRecord: projectRecord,
 61→          text: input.rationale,
 62→        }).catch(() => undefined);
 63→
 64→        await createExtractionProvenanceEdge({
 65→          surreal: deps.surreal,
