165→            },
166→          }).catch(() => undefined);
167→        } catch {
168→          // project resolution is best-effort
169→        }
170→      }
171→
172→      void seedDescriptionEntry({
173→        surreal: deps.surreal,
174→        targetRecord: featureRecord,
175→        text: input.rationale,
176→      }).catch(() => undefined);
177→
178→      await createExtractionProvenanceEdge({
179→        surreal: deps.surreal,
