 1→import { tool } from "ai";
 2→import { z } from "zod";
 3→import { getProjectStatus } from "../../graph/queries";
 4→import { requireToolContext } from "./helpers";
 5→import type { ChatToolDeps } from "./types";
 6→
 7→export function createGetProjectStatusTool(deps: ChatToolDeps) {
 8→  return tool({
 9→    description:
10→      "Get the current status of a project including active tasks, recent decisions, open questions, and features.",
11→    inputSchema: z.object({
12→      projectId: z.string().min(1).describe("Project record ID or project name"),
13→    }),
14→    execute: async (input, options) => {
15→      const context = requireToolContext(options);
16→
17→      return getProjectStatus({
18→        surreal: deps.surreal,
19→        workspaceRecord: context.workspaceRecord,
20→        projectInput: input.projectId,
21→      });
22→    },
23→  });
24→}
