150→   150→export function parseRecordIdString<T extends string>(
151→   151→  value: string,
152→   152→  allowedTables: T[],
153→   153→  fallbackTable?: T,
154→   154→): RecordId<T, string> {
155→   155→  const normalized = value.trim();
156→   156→  if (normalized.length === 0) {
157→   157→    throw new Error("record id is required");
158→   158→  }
159→   159→
160→   160→  const separatorIndex = normalized.indexOf(":");
161→   161→  if (separatorIndex === -1) {
162→   162→    if (!fallbackTable) {
163→   163→      throw new Error(`record id must be prefixed with one of: ${allowedTables.join(", ")}`);
164→   164→    }
165→   165→
166→   166→    return new RecordId(fallbackTable, normalized) as RecordId<T, string>;
167→   167→  }
168→   168→
169→   169→  const table = normalized.slice(0, separatorIndex) as T;
170→   170→  const id = normalized.slice(separatorIndex + 1);
171→   171→  if (!allowedTables.includes(table)) {
172→   172→    throw new Error(`record id table must be one of: ${allowedTables.join(", ")}`);
173→   173→  }
174→   174→
175→   175→  if (id.length === 0) {
176→   176→    throw new Error("record id is missing its identifier component");
177→   177→  }
178→   178→
179→   179→  return new RecordId(table, id) as RecordId<T, string>;
180→   180→}
