  1→import { RecordId } from "surrealdb";
  2→import { ENTITY_PRIORITIES, type EntityActionRequest } from "../../shared/contracts";
  3→import { HttpError } from "../http/errors";
  4→import { logError, logInfo } from "../http/observability";
  5→import { jsonError, jsonResponse } from "../http/response";
  6→import { acknowledgeObservation, resolveObservation } from "../observation/queries";
  7→import type { ServerDependencies } from "../runtime/types";
  8→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  9→import {
 10→  confirmDecisionRecord,
 11→  isEntityInWorkspace,
 12→  parseRecordIdString,
 13→  type GraphEntityTable,
 14→} from "../graph/queries";
 15→import { fireDescriptionUpdates } from "../descriptions/triggers";
 16→
 17→type EntityActionTable = GraphEntityTable | "observation";
 18→
 19→export function createEntityActionsHandler(
 20→  deps: ServerDependencies,
 21→): (entityId: string, request: Request) => Promise<Response> {
 22→  return (entityId: string, request: Request) => handleEntityAction(deps, entityId, request);
 23→}
 24→
 25→async function handleEntityAction(
 26→  deps: ServerDependencies,
 27→  entityId: string,
 28→  request: Request,
 29→): Promise<Response> {
 30→  let body: EntityActionRequest;
 31→  try {
 32→    body = await request.json() as EntityActionRequest;
 33→  } catch {
 34→    return jsonError("invalid JSON body", 400);
 35→  }
 36→
 37→  if (!body.action || !["confirm", "override", "complete", "set_priority", "acknowledge", "resolve", "dismiss"].includes(body.action)) {
 38→    return jsonError("action must be one of: confirm, override, complete, set_priority, acknowledge, resolve, dismiss", 400);
 39→  }
 40→
 41→  const url = new URL(request.url);
 42→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 43→  if (!workspaceId) {
 44→    return jsonError("workspaceId is required", 400);
 45→  }
 46→
 47→  let workspaceRecord;
 48→  try {
 49→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 50→  } catch (error) {
 51→    if (error instanceof HttpError) {
 52→      return jsonError(error.message, error.status);
 53→    }
 54→    logError("entity.action.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 55→    return jsonError("failed to resolve workspace", 500);
 56→  }
 57→
 58→  try {
 59→    const entityTables: EntityActionTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation"];
 60→    const entityRecord = parseRecordIdString(entityId, entityTables);
 61→
 62→    const table = entityRecord.table.name;
 63→    const now = new Date();
 64→
 65→    // Observation actions have separate handlers from task/decision/question.
 66→    if (table === "observation") {
 67→      if (body.action === "acknowledge") {
 68→        await acknowledgeObservation({
 69→          surreal: deps.surreal,
 70→          workspaceRecord,
 71→          observationRecord: entityRecord as RecordId<"observation", string>,
 72→          now,
 73→        });
 74→        logInfo("entity.action.acknowledge", "Observation acknowledged", { workspaceId, entityId });
 75→        return jsonResponse({ status: "acknowledged" }, 200);
 76→      }
 77→
 78→      if (body.action === "resolve") {
 79→        await resolveObservation({
 80→          surreal: deps.surreal,
 81→          workspaceRecord,
 82→          observationRecord: entityRecord as RecordId<"observation", string>,
 83→          now,
 84→        });
 85→        logInfo("entity.action.resolve", "Observation resolved", { workspaceId, entityId });
 86→        return jsonResponse({ status: "resolved" }, 200);
 87→      }
 88→
 89→      return jsonError(`action '${body.action}' is not valid for entity type 'observation'`, 400);
 90→    }
 91→
 92→    const scoped = await isEntityInWorkspace(deps.surreal, workspaceRecord, entityRecord as RecordId<GraphEntityTable, string>);
 93→    if (!scoped) {
 94→      return jsonError("entity is outside the current workspace scope", 403);
 95→    }
 96→
 97→    if (body.action === "confirm" && table === "decision") {
 98→      const [decisionRows] = await deps.surreal
 99→        .query<[Array<{ summary: string }>]>(
100→          "SELECT summary FROM $record LIMIT 1;",
101→          { record: entityRecord },
102→        )
103→        .collect<[Array<{ summary: string }>]>();
104→      const decisionSummary = decisionRows[0]?.summary ?? entityId;
105→
106→      await confirmDecisionRecord({
107→        surreal: deps.surreal,
108→        decisionRecord: entityRecord as RecordId<"decision", string>,
109→        confirmedAt: now,
110→        notes: body.notes,
111→      });
112→
113→      void fireDescriptionUpdates({
114→        surreal: deps.surreal,
115→        extractionModel: deps.extractionModel,
116→        trigger: {
117→          kind: "decision_confirmed",
118→          entity: entityRecord,
119→          summary: `Decision confirmed: ${decisionSummary}`,
120→        },
121→      }).catch(() => undefined);
122→
123→      logInfo("entity.action.confirm", "Decision confirmed", { workspaceId, entityId });
124→      return jsonResponse({ status: "confirmed" }, 200);
125→    }
126→
127→    if (body.action === "override" && table === "decision") {
128→      if (!body.newSummary) {
129→        return jsonError("newSummary is required for override action", 400);
130→      }
131→      await deps.surreal.update(entityRecord as RecordId<"decision", string>).merge({
132→        summary: body.newSummary,
133→        status: "overridden",
134→        updated_at: now,
135→        ...(body.notes ? { override_notes: body.notes } : {}),
136→      });
137→      logInfo("entity.action.override", "Decision overridden", { workspaceId, entityId });
138→      return jsonResponse({ status: "overridden" }, 200);
139→    }
140→
141→    if (body.action === "complete" && table === "feature") {
142→      const [featureRows] = await deps.surreal
143→        .query<[Array<{ name: string }>]>(
144→          "SELECT name FROM $record LIMIT 1;",
145→          { record: entityRecord },
146→        )
147→        .collect<[Array<{ name: string }>]>();
148→      const featureName = featureRows[0]?.name ?? entityId;
149→
150→      await deps.surreal.update(entityRecord as RecordId<"feature", string>).merge({
151→        status: "done",
152→        updated_at: now,
153→      });
154→
155→      void fireDescriptionUpdates({
156→        surreal: deps.surreal,
157→        extractionModel: deps.extractionModel,
158→        trigger: {
159→          kind: "feature_completed",
160→          entity: entityRecord,
161→          summary: `Feature completed: ${featureName}`,
162→        },
163→      }).catch(() => undefined);
164→
165→      logInfo("entity.action.complete", "Feature completed", { workspaceId, entityId });
166→      return jsonResponse({ status: "completed" }, 200);
167→    }
168→
169→    if (body.action === "complete" && table === "task") {
170→      const [taskRows] = await deps.surreal
171→        .query<[Array<{ title: string }>]>(
172→          "SELECT title FROM $record LIMIT 1;",
173→          { record: entityRecord },
174→        )
175→        .collect<[Array<{ title: string }>]>();
176→      const taskTitle = taskRows[0]?.title ?? entityId;
177→
178→      await deps.surreal.update(entityRecord as RecordId<"task", string>).merge({
179→        status: "done",
180→        completed_at: now,
181→        updated_at: now,
182→      });
183→
184→      void fireDescriptionUpdates({
185→        surreal: deps.surreal,
186→        extractionModel: deps.extractionModel,
187→        trigger: {
188→          kind: "task_completed",
189→          entity: entityRecord,
190→          summary: `Task completed: ${taskTitle}`,
191→        },
192→      }).catch(() => undefined);
193→
194→      logInfo("entity.action.complete", "Task completed", { workspaceId, entityId });
195→      return jsonResponse({ status: "completed" }, 200);
196→    }
197→
198→    if (body.action === "dismiss" && table === "question") {
199→      await deps.surreal.update(entityRecord as RecordId<"question", string>).merge({
200→        status: "dismissed",
201→        updated_at: now,
202→      });
203→      logInfo("entity.action.dismiss", "Question dismissed", { workspaceId, entityId });
204→      return jsonResponse({ status: "dismissed" }, 200);
205→    }
206→
207→    if (body.action === "set_priority" && (table === "task" || table === "decision" || table === "question")) {
208→      if (!body.priority || !(ENTITY_PRIORITIES as readonly string[]).includes(body.priority)) {
209→        return jsonError("priority must be one of: low, medium, high, critical", 400);
210→      }
211→      await deps.surreal.update(entityRecord).merge({
212→        priority: body.priority,
213→        updated_at: now,
214→      });
215→      logInfo("entity.action.set_priority", "Priority updated", { workspaceId, entityId, priority: body.priority });
216→      return jsonResponse({ status: "priority_updated", priority: body.priority }, 200);
217→    }
218→
219→    return jsonError(`action '${body.action}' is not valid for entity type '${table}'`, 400);
220→  } catch (error) {
221→    logError("entity.action.failed", "Entity action failed", error, {
222→      workspaceId,
223→      entityId,
224→      action: body.action,
225→    });
226→    const message = error instanceof Error ? error.message : "entity action failed";
227→    return jsonError(message, 500);
228→  }
229→}
