  9→type SearchEntityRow = {
 10→  id: RecordId<string, string>;
 11→  kind: EntityKind;
 12→  text: string;
 13→  score: number;
 14→};
 15→
 16→// BM25 full-text search queries per entity type.
 17→// Queries run from app layer because:
 18→// 1. search::score() / @N@ don't work inside DEFINE FUNCTION (https://github.com/surrealdb/surrealdb/issues/7013)
 19→// 2. @N@ doesn't work with SDK bound parameters — search term must be a string literal
 20→
 21→function escapeSearchQuery(query: string): string {
 22→  return query.replace(/\\/g, "\\\\").replace(/'/g, "\\'");
 23→}
 24→
 25→function buildWorkspaceSearchSQL(escapedQuery: string): string {
 26→  const q = `'${escapedQuery}'`;
 27→  return `
 28→SELECT id, "task" AS kind, title AS text, search::score(1) AS score
 29→FROM task WHERE title @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 30→
 31→SELECT id, "decision" AS kind, summary AS text, search::score(1) AS score
 32→FROM decision WHERE summary @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 33→
 34→SELECT id, "question" AS kind, text AS text, search::score(1) AS score
 35→FROM question WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 36→
 37→SELECT id, "observation" AS kind, text AS text, search::score(1) AS score
 38→FROM observation WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 39→
 40→SELECT id, "feature" AS kind, name AS text, search::score(1) AS score
 41→FROM feature WHERE name @1@ ${q} ORDER BY score DESC LIMIT $limit;
 42→
 43→SELECT id, "project" AS kind, name AS text, search::score(1) AS score
 44→FROM project WHERE name @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 45→
 46→SELECT id, "person" AS kind, name AS text, search::score(1) AS score
 47→FROM person WHERE name @1@ ${q} ORDER BY score DESC LIMIT $limit;
 48→
 49→SELECT id, "message" AS kind, text AS text, search::score(1) AS score
 50→FROM message WHERE text @1@ ${q} AND conversation.workspace = $workspace ORDER BY score DESC LIMIT $limit;
 51→`;
 52→}
 53→
 54→function buildProjectSearchSQL(escapedQuery: string): string {
 55→  const q = `'${escapedQuery}'`;
 56→  return `
 57→LET $project_entity_ids = SELECT VALUE in FROM belongs_to WHERE out = $project;
 58→
 59→SELECT id, "task" AS kind, title AS text, search::score(1) AS score
 60→FROM task WHERE title @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 61→
 62→SELECT id, "decision" AS kind, summary AS text, search::score(1) AS score
 63→FROM decision WHERE summary @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 64→
 65→SELECT id, "question" AS kind, text AS text, search::score(1) AS score
 66→FROM question WHERE text @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 67→
 68→SELECT id, "observation" AS kind, text AS text, search::score(1) AS score
 69→FROM observation WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 70→
 71→SELECT id, "feature" AS kind, name AS text, search::score(1) AS score
 72→FROM feature WHERE name @1@ ${q} AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 73→
 74→SELECT id, "message" AS kind, text AS text, search::score(1) AS score
 75→FROM message WHERE text @1@ ${q} AND conversation.workspace = $workspace ORDER BY score DESC LIMIT $limit;
 76→`;
 77→}
