 83→async function handleEntitySearch(deps: ServerDependencies, url: URL): Promise<Response> {
 84→  const startedAt = performance.now();
 85→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 86→  if (!workspaceId) {
 87→    return jsonError("workspaceId is required", 400);
 88→  }
 89→
 90→  const projectId = url.searchParams.get("projectId")?.trim();
 91→
 92→  const query = url.searchParams.get("q")?.trim();
 93→  if (!query) {
 94→    return jsonError("q is required", 400);
 95→  }
 96→
 97→  const rawLimit = url.searchParams.get("limit");
 98→  const parsedLimit = Number(rawLimit ?? "10");
 99→  if (!Number.isFinite(parsedLimit) || parsedLimit < 1) {
100→    return jsonError("limit must be a positive number", 400);
101→  }
102→
103→  const limit = Math.min(Math.floor(parsedLimit), 100);
104→  logDebug("http.request.validated", "Entity search request validated", {
105→    workspaceId,
106→    projectId,
107→    limit,
108→    queryLength: query.length,
109→  });
110→  logInfo("entity.search.started", "Entity search started", {
111→    workspaceId,
112→    projectId,
113→    limit,
114→  });
115→
116→  let workspaceRecord: RecordId<"workspace", string>;
117→  let projectRecord: RecordId<"project", string> | undefined;
118→
119→  try {
120→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
121→    if (projectId) {
122→      projectRecord = await resolveWorkspaceProjectRecord(deps.surreal, workspaceRecord, projectId);
123→    }
124→  } catch (error) {
125→    if (error instanceof HttpError) {
126→      logWarn("entity.search.http_error", "Entity search failed with client-facing error", {
127→        workspaceId,
128→        projectId,
129→        statusCode: error.status,
130→      });
131→      return jsonError(error.message, error.status);
132→    }
133→
134→    logError("entity.search.scope_validation.failed", "Entity search scope validation failed", error, {
135→      workspaceId,
136→      projectId,
137→    });
138→    const errorText = error instanceof Error ? error.message : "failed to validate scope";
139→    return jsonError(errorText, 500);
140→  }
141→
142→  const escaped = escapeSearchQuery(query);
143→  const sql = projectRecord
144→    ? buildProjectSearchSQL(escaped)
145→    : buildWorkspaceSearchSQL(escaped);
146→
147→  const bindings = {
148→    limit,
149→    workspace: workspaceRecord,
150→    ...(projectRecord ? { project: projectRecord } : {}),
151→  };
152→
153→  const results = await deps.surreal.query(sql, bindings);
154→
155→  const allRows = (results as unknown as SearchEntityRow[][])
156→    .filter(Array.isArray)
157→    .flat()
158→    .sort((a, b) => b.score - a.score)
159→    .slice(0, limit);
160→
161→  const responseRows = allRows.map((row) => ({
162→    id: row.id.id as string,
163→    kind: row.kind,
164→    text: row.text,
165→    confidence: row.score,
166→    sourceId: "",
167→    sourceKind: "message",
168→  } satisfies SearchEntityResponse));
169→
170→  logInfo("entity.search.completed", "Entity search completed", {
171→    workspaceId,
172→    projectId,
173→    limit,
174→    resultCount: responseRows.length,
175→    durationMs: elapsedMs(startedAt),
176→  });
177→
178→  return jsonResponse(responseRows, 200);
179→}
