 40→async function handleFeed(deps: ServerDependencies, workspaceId: string): Promise<Response> {
 41→  const startedAt = performance.now();
 42→  logInfo("feed.started", "Governance feed request started", { workspaceId });
 43→
 44→  let workspaceRecord: RecordId<"workspace", string>;
 45→  try {
 46→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 47→  } catch (error) {
 48→    if (error instanceof HttpError) {
 49→      logWarn("feed.workspace_resolve.http_error", "Feed workspace resolve failed", {
 50→        workspaceId,
 51→        statusCode: error.status,
 52→      });
 53→      return jsonError(error.message, error.status);
 54→    }
 55→    logError("feed.workspace_resolve.failed", "Feed workspace resolve failed", error, { workspaceId });
 56→    return jsonError("failed to resolve workspace", 500);
 57→  }
 58→
 59→  try {
 60→    const queryInput = { surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT };
 61→
 62→    const [
 63→      provisionalDecisions,
 64→      conflicts,
 65→      blockingQuestions,
 66→      lowConfidenceDecisions,
 67→      blockedTasks,
 68→      observations,
 69→      staleTasks,
 70→      recentlyCompleted,
 71→      recentExtractions,
 72→    ] = await Promise.all([
 73→      listProvisionalDecisions(queryInput),
 74→      listWorkspaceConflicts(queryInput),
 75→      listBlockingQuestions(queryInput),
 76→      listLowConfidenceDecisions({ ...queryInput, confidenceThreshold: LOW_CONFIDENCE_THRESHOLD }),
 77→      listBlockedTasks(queryInput),
 78→      listWorkspaceOpenObservations({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
 79→      listStaleTasks({ ...queryInput, staleDays: STALE_DAYS }),
 80→      listRecentlyCompletedItems({ ...queryInput, recentDays: RECENT_COMPLETED_DAYS }),
 81→      listRecentExtractions({ ...queryInput, cutoff: new Date(Date.now() - AWARENESS_RECENCY_DAYS * 24 * 60 * 60 * 1000) }),
 82→    ]);
 83→
 84→    const blocking: GovernanceFeedItem[] = [];
 85→    const review: GovernanceFeedItem[] = [];
 86→    const awareness: GovernanceFeedItem[] = [];
 87→
 88→    // Blocking: provisional decisions
 89→    for (const row of provisionalDecisions) {
 90→      const rawId = row.id.id as string;
 91→      blocking.push({
 92→        id: `decision:${rawId}:${row.status}`,
 93→        tier: "blocking",
 94→        entityId: `decision:${rawId}`,
 95→        entityKind: "decision",
 96→        entityName: row.summary,
 97→        reason: `${capitalize(row.status)} decision awaiting confirmation`,
 98→        status: row.status,
 99→        ...(row.project ? { project: row.project } : {}),
100→        ...(row.category ? { category: row.category as EntityCategory } : {}),
101→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
102→        createdAt: toIsoString(row.created_at),
103→        actions: decisionActions(),
104→      });
105→    }
106→
107→    // Blocking: conflicts
108→    for (const row of conflicts) {
109→      blocking.push({
110→        id: `conflict:${row.edgeId}`,
111→        tier: "blocking",
112→        entityId: `${row.fromKind}:${row.fromRecord.id as string}`,
113→        entityKind: row.fromKind as EntityKind,
114→        entityName: row.fromName,
115→        reason: row.description ?? `Conflicts with ${row.toName}`,
116→        status: "conflict",
117→        ...(row.severity ? { severity: row.severity as ObservationSeverity } : {}),
118→        createdAt: row.detectedAt,
119→        actions: conflictActions(),
120→        conflictTarget: {
121→          entityId: `${row.toKind}:${row.toRecord.id as string}`,
122→          entityKind: row.toKind as EntityKind,
123→          entityName: row.toName,
124→        },
125→      });
126→    }
127→
128→    // Blocking: high/critical questions
129→    for (const row of blockingQuestions) {
130→      const rawId = row.id.id as string;
131→      blocking.push({
132→        id: `question:${rawId}:blocking`,
133→        tier: "blocking",
134→        entityId: `question:${rawId}`,
135→        entityKind: "question",
136→        entityName: row.text,
137→        reason: `${capitalize(row.priority)} priority open question`,
138→        status: row.status,
139→        ...(row.project ? { project: row.project } : {}),
140→        ...(row.category ? { category: row.category as EntityCategory } : {}),
141→        priority: row.priority as EntityPriority,
142→        createdAt: toIsoString(row.created_at),
143→        actions: questionActions(),
144→      });
145→    }
146→
147→    // Review: low confidence decisions
148→    for (const row of lowConfidenceDecisions) {
149→      const rawId = row.id.id as string;
150→      review.push({
151→        id: `decision:${rawId}:low_confidence`,
152→        tier: "review",
153→        entityId: `decision:${rawId}`,
154→        entityKind: "decision",
155→        entityName: row.summary,
156→        reason: `Low confidence inferred decision (${Math.round(row.extraction_confidence * 100)}%)`,
157→        status: row.status,
158→        ...(row.project ? { project: row.project } : {}),
159→        ...(row.category ? { category: row.category as EntityCategory } : {}),
160→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
161→        createdAt: toIsoString(row.created_at),
162→        actions: decisionActions(),
163→      });
164→    }
165→
166→    // Review: blocked tasks
167→    for (const row of blockedTasks) {
168→      const rawId = row.id.id as string;
169→      review.push({
170→        id: `task:${rawId}:blocked`,
171→        tier: "review",
172→        entityId: `task:${rawId}`,
173→        entityKind: "task",
174→        entityName: row.title,
175→        reason: "Task is blocked",
176→        status: row.status,
177→        ...(row.project ? { project: row.project } : {}),
178→        ...(row.category ? { category: row.category as EntityCategory } : {}),
179→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
180→        createdAt: toIsoString(row.created_at),
181→        actions: blockedTaskActions(),
182→      });
183→    }
184→
185→    // Review: all open/acknowledged observations need human action
186→    for (const obs of observations) {
187→      review.push({
188→        id: `observation:${obs.id}:${obs.severity}`,
189→        tier: "review",
190→        entityId: `observation:${obs.id}`,
191→        entityKind: "observation",
192→        entityName: obs.text,
193→        reason: `${capitalize(obs.severity)} observation from ${obs.sourceAgent}`,
194→        status: obs.status,
195→        ...(obs.category ? { category: obs.category } : {}),
196→        severity: obs.severity,
197→        createdAt: obs.createdAt,
198→        actions: observationActions(obs.status),
199→      });
200→    }
201→
202→    // Awareness items are filtered to the last AWARENESS_RECENCY_DAYS
203→    const awarenessCutoff = new Date(Date.now() - AWARENESS_RECENCY_DAYS * 24 * 60 * 60 * 1000);
204→
205→    // Awareness: stale tasks (only if they crossed the stale threshold recently)
206→    for (const row of staleTasks) {
207→      const ts = row.updated_at ? new Date(row.updated_at) : new Date(row.created_at);
208→      if (ts < awarenessCutoff) continue;
209→      const rawId = row.id.id as string;
210→      awareness.push({
211→        id: `task:${rawId}:stale`,
212→        tier: "awareness",
213→        entityId: `task:${rawId}`,
214→        entityKind: "task",
215→        entityName: row.title,
216→        reason: `Task open for over ${STALE_DAYS} days`,
217→        status: row.status,
218→        ...(row.project ? { project: row.project } : {}),
219→        ...(row.category ? { category: row.category as EntityCategory } : {}),
220→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
221→        createdAt: toIsoString(row.created_at),
222→        actions: staleTaskActions(),
223→      });
224→    }
225→
226→    // Awareness: recently completed (already filtered by RECENT_COMPLETED_DAYS query)
227→    for (const row of recentlyCompleted) {
228→      const rawId = row.id.id as string;
229→      awareness.push({
230→        id: `${row.kind}:${rawId}:completed`,
231→        tier: "awareness",
232→        entityId: `${row.kind}:${rawId}`,
233→        entityKind: row.kind as EntityKind,
234→        entityName: row.name,
235→        reason: `Recently completed ${row.kind}`,
236→        status: row.status,
237→        ...(row.project ? { project: row.project } : {}),
238→        ...(row.category ? { category: row.category as EntityCategory } : {}),
239→        createdAt: toIsoString(row.updated_at),
240→        actions: [],
241→      });
242→    }
243→
244→    // Awareness: recent extractions (skip entities already in higher tiers)
245→    const seenEntityIds = new Set<string>();
246→    for (const item of [...blocking, ...review, ...awareness]) {
247→      seenEntityIds.add(item.entityId);
248→    }
249→    for (const row of recentExtractions) {
250→      const entityId = `${row.entityKind}:${row.entityId}`;
251→      if (seenEntityIds.has(entityId)) continue;
252→      awareness.push({
253→        id: `extraction:${row.edgeId}`,
254→        tier: "awareness",
255→        entityId,
256→        entityKind: row.entityKind as EntityKind,
257→        entityName: row.entityName,
258→        reason: `Extracted from ${row.sourceKind.replace("_", " ")}`,
259→        status: "extracted",
260→        createdAt: row.extractedAt,
261→        actions: row.entityKind === "question" ? questionActions() : [],
262→      });
263→    }
264→
265→    const payload: GovernanceFeedResponse = {
266→      blocking,
267→      review,
268→      awareness,
269→      updatedAt: new Date().toISOString(),
270→    };
271→
272→    logInfo("feed.completed", "Governance feed request completed", {
273→      workspaceId,
274→      blockingCount: blocking.length,
275→      reviewCount: review.length,
276→      awarenessCount: awareness.length,
277→      durationMs: elapsedMs(startedAt),
278→    });
279→
280→    return jsonResponse(payload, 200);
281→  } catch (error) {
282→    logError("feed.failed", "Governance feed request failed", error, { workspaceId });
283→    const message = error instanceof Error ? error.message : "feed request failed";
284→    return jsonError(message, 500);
285→  }
286→}
