235→   235→export async function isEntityInWorkspace(
236→   236→  surreal: Surreal,
237→   237→  workspaceRecord: RecordId<"workspace", string>,
238→   238→  entityRecord: GraphEntityRecord,
239→   239→): Promise<boolean> {
240→   240→  const table = entityRecord.table.name;
241→   241→
242→   242→  if (table === "workspace") {
243→   243→    return toRecordIdString(entityRecord) === toRecordIdString(workspaceRecord);
244→   244→  }
245→   245→
246→   246→  if (table === "project") {
247→   247→    const [rows] = await surreal
248→   248→      .query<[Array<{ id: RecordId<"has_project", string> }>]>(
249→   249→        "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
250→   250→        { workspace: workspaceRecord, project: entityRecord },
251→   251→      )
252→   252→      .collect<[Array<{ id: RecordId<"has_project", string> }>]>();
253→   253→
254→   254→    return rows.length > 0;
255→   255→  }
256→   256→
257→   257→  if (table === "person") {
258→   258→    const [rows] = await surreal
259→   259→      .query<[Array<{ id: RecordId<"member_of", string> }>]>(
260→   260→        "SELECT id FROM member_of WHERE `in` = $person AND out = $workspace LIMIT 1;",
261→   261→        { workspace: workspaceRecord, person: entityRecord },
262→   262→      )
263→   263→      .collect<[Array<{ id: RecordId<"member_of", string> }>]>();
264→   264→
265→   265→    return rows.length > 0;
266→   266→  }
267→   267→
268→   268→  if (table === "feature") {
269→   269→    const [rows] = await surreal
270→   270→      .query<[Array<{ id: RecordId<"feature", string> }>]>(
271→   271→        [
272→   272→          "SELECT id",
273→   273→          "FROM feature",
274→   274→          "WHERE id = $feature",
275→   275→          "AND id IN (",
276→   276→          "  SELECT VALUE out",
277→   277→          "  FROM has_feature",
278→   278→          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
279→   279→          ");",
280→   280→        ].join(" "),
281→   281→        { workspace: workspaceRecord, feature: entityRecord },
282→   282→      )
283→   283→      .collect<[Array<{ id: RecordId<"feature", string> }>]>();
284→   284→
285→   285→    return rows.length > 0;
286→   286→  }
287→   287→
288→   288→  if (table === "task" || table === "decision" || table === "question") {
289→   289→    const [rows] = await surreal
290→   290→      .query<[Array<{ id: RecordId<"task" | "decision" | "question", string> }>]>(
291→   291→        `SELECT id FROM ${table} WHERE id = $entity AND workspace = $workspace;`,
292→   292→        { workspace: workspaceRecord, entity: entityRecord },
293→   293→      )
294→   294→      .collect<[Array<{ id: RecordId<"task" | "decision" | "question", string> }>]>();
295→   295→
296→   296→    return rows.length > 0;
297→   297→  }
298→   298→
299→   299→  return false;
300→   300→}
