314→   314→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
315→   315→        "ORDER BY extracted_at DESC",
316→   316→        "LIMIT $limit;",
317→   317→      ].join(" "),
318→   318→      {
319→   319→        conversation: input.conversationRecord,
320→   320→        limit: input.limit,
321→   321→      },
322→   322→    )
323→   323→    .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>() ;
324→   324→
325→   325→  const items: ConversationEntity[] = [];
326→   326→  const seen = new Set<string>();
327→   327→
328→   328→  for (const row of rows) {
329→   329→    const table = row.out.table.name as GraphEntityTable;
330→   330→    if (
331→   331→      table !== "workspace" &&
332→   332→      table !== "project" &&
333→   333→      table !== "person" &&
334→   334→      table !== "feature" &&
335→   335→      table !== "task" &&
336→   336→      table !== "decision" &&
337→   337→      table !== "question"
338→   338→    ) {
339→   339→      continue;
340→   340→    }
341→   341→
342→   342→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, row.out);
343→   343→    if (!scoped) {
344→   344→      continue;
345→   345→    }
346→   346→
347→   347→    const entityKey = `${table}:${toRecordIdString(row.out)}`;
348→   348→    if (seen.has(entityKey)) {
349→   349→      continue;
350→   350→    }
351→   351→
352→   352→    const name = await readEntityName(input.surreal, row.out);
353→   353→    if (!name) {
354→   354→      continue;
355→   355→    }
356→   356→
357→   357→    items.push({
358→   358→      id: toRecordIdString(row.out),
359→   359→      kind: table,
360→   360→      name,
361→   361→      confidence: row.confidence,
362→   362→      sourceMessageId: toRecordIdString(row.in),
363→   363→    });
364→   364→    seen.add(entityKey);
365→   365→  }
366→   366→
367→   367→  // Merge inherited entities from parent conversation when branch has sparse context
368→   368→  if (input.inheritedEntityIds && input.inheritedEntityIds.length > 0 && items.length < 5) {
369→   369→    const [inheritedRows] = await input.surreal
370→   370→      .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
371→   371→        [
372→   372→          "SELECT `in`, out, confidence, extracted_at",
373→   373→          "FROM extraction_relation",
374→   374→          "WHERE out IN $entityIds",
375→   375→          "ORDER BY extracted_at DESC",
376→   376→          "LIMIT $limit;",
377→   377→        ].join(" "),
378→   378→        { entityIds: input.inheritedEntityIds, limit: input.limit },
379→   379→      )
380→   380→      .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>();
381→   381→
382→   382→    for (const row of inheritedRows) {
383→   383→      const table = row.out.table.name as GraphEntityTable;
384→   384→      if (
385→   385→        table !== "workspace" &&
386→   386→        table !== "project" &&
387→   387→        table !== "person" &&
388→   388→        table !== "feature" &&
389→   389→        table !== "task" &&
390→   390→        table !== "decision" &&
391→   391→        table !== "question"
392→   392→      ) {
393→   393→        continue;
394→   394→      }
395→   395→
396→   396→      const entityKey = `${table}:${toRecordIdString(row.out)}`;
397→   397→      if (seen.has(entityKey)) continue;
398→   398→
399→   399→      const name = await readEntityName(input.surreal, row.out);
400→   400→      if (!name) continue;
401→   401→
402→   402→      items.push({
403→   403→        id: toRecordIdString(row.out),
404→   404→        kind: table,
405→   405→        name,
406→   406→        confidence: row.confidence,
407→   407→        sourceMessageId: toRecordIdString(row.in),
408→   408→      });
409→   409→      seen.add(entityKey);
410→   410→    }
411→   411→  }
412→   412→
413→   413→  return items;
414→   414→}
