560→   560→export async function resolveWorkspaceProjectRecord(input: {
561→   561→  surreal: Surreal;
562→   562→  workspaceRecord: RecordId<"workspace", string>;
563→   563→  projectInput: string;
564→   564→}): Promise<RecordId<"project", string>> {
565→   565→  const projectInput = input.projectInput.trim();
566→   566→  if (projectInput.length === 0) {
567→   567→    throw new Error("project identifier is required");
568→   568→  }
569→   569→
570→   570→  if (projectInput.includes(":")) {
571→   571→    const projectRecord = parseRecordIdString(projectInput, ["project"]);
572→   572→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, projectRecord);
573→   573→    if (!scoped) {
574→   574→      throw new Error("project is not linked to this workspace");
575→   575→    }
576→   576→    return projectRecord;
577→   577→  }
578→   578→
579→   579→  const projects = await getWorkspaceProjectRows(input.surreal, input.workspaceRecord);
580→   580→  const normalized = normalizeSearchValue(projectInput);
581→   581→
582→   582→  const exactMatch = projects.find((project) => normalizeSearchValue(project.name) === normalized);
583→   583→  if (exactMatch) {
584→   584→    return exactMatch.id;
585→   585→  }
586→   586→
587→   587→  const fuzzyMatches = projects.filter((project) => normalizeSearchValue(project.name).includes(normalized));
588→   588→  if (fuzzyMatches.length === 1) {
589→   589→    return fuzzyMatches[0].id;
590→   590→  }
591→   591→
592→   592→  if (fuzzyMatches.length > 1) {
593→   593→    throw new Error(`project input is ambiguous: ${fuzzyMatches.map((project) => project.name).join(", ")}`);
594→   594→  }
595→   595→
596→   596→  throw new Error(`project not found in workspace: ${projectInput}`);
597→   597→}
