 8→    case "feature": return "#14b8a6";   // oklch(0.65 0.15 170)
 9→    case "task": return "#22c55e";      // oklch(0.70 0.15 145)
10→    case "decision": return "#eab308";  // oklch(0.70 0.15 55)
