12→    case "observation": return "#ef4444";
13→    case "person": return "#f97316";    // oklch(0.65 0.15 25)
14→    case "workspace": return "#3b82f6";
15→    case "message": return "#22c55e";
16→  }
17→}
18→
19→function titleCase(s: string): string {
20→  return s.split(" ").map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
21→}
22→
23→export function transformToReagraph(raw: GraphViewRawResult): GraphResponse {
24→  const connectionCounts = new Map<string, number>();
25→  for (const edge of raw.edges) {
26→    connectionCounts.set(edge.fromId, (connectionCounts.get(edge.fromId) ?? 0) + 1);
27→    connectionCounts.set(edge.toId, (connectionCounts.get(edge.toId) ?? 0) + 1);
28→  }
29→
30→  const nodes: ReagraphNode[] = raw.entities.map((entity) => {
31→    const kind = entity.kind as EntityKind;
32→    const kindBoost = kind === "project" ? 20
33→      : kind === "feature" ? 10
34→      : kind === "person" ? 8
35→      : 0;
36→    return {
37→      id: entity.id,
38→      label: entity.name.length > 32 ? entity.name.slice(0, 32) + "\u2026" : entity.name,
39→      fill: entityColor(kind),
40→      data: {
41→        kind,
42→        connectionCount: (connectionCounts.get(entity.id) ?? 0) + kindBoost,
43→        status: undefined,
44→      },
45→    };
46→  });
47→
48→  const edges: ReagraphEdge[] = raw.edges.map((edge) => ({
49→    id: edge.id,
50→    source: edge.fromId,
51→    target: edge.toId,
52→    label: titleCase(edge.kind.replace(/_/g, " ")),
53→    data: {
54→      type: edge.kind,
55→      confidence: edge.confidence,
56→    },
57→  }));
58→
59→  return { nodes, edges };
60→}
