408→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
409→  LET $query = string::lowercase(string::trim($q));
410→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
411→
412→  LET $task_rows = SELECT
413→    id,
414→    "task" AS kind,
415→    title AS text,
416→    extraction_confidence AS confidence,
417→    source_message AS sourceMessage,
418→    priority,
419→    created_at
420→  FROM task
421→  WHERE workspace = $workspace
422→    AND extraction_confidence != NONE
423→    AND string::contains(string::lowercase(title), $query)
424→  ORDER BY created_at DESC
425→  LIMIT $safe_limit;
426→
427→  LET $decision_rows = SELECT
428→    id,
429→    "decision" AS kind,
430→    summary AS text,
431→    extraction_confidence AS confidence,
432→    source_message AS sourceMessage,
433→    priority,
434→    created_at
435→  FROM decision
436→  WHERE workspace = $workspace
437→    AND extraction_confidence != NONE
438→    AND string::contains(string::lowercase(summary), $query)
439→  ORDER BY created_at DESC
440→  LIMIT $safe_limit;
441→
442→  LET $question_rows = SELECT
443→    id,
444→    "question" AS kind,
445→    text AS text,
446→    extraction_confidence AS confidence,
447→    source_message AS sourceMessage,
448→    priority,
449→    created_at
450→  FROM question
451→  WHERE workspace = $workspace
452→    AND extraction_confidence != NONE
453→    AND string::contains(string::lowercase(text), $query)
454→  ORDER BY created_at DESC
455→  LIMIT $safe_limit;
456→
457→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
458→};
459→
460→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
461→  LET $query = string::lowercase(string::trim($q));
462→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
463→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
464→
465→  LET $task_rows = SELECT
466→    id,
467→    "task" AS kind,
468→    title AS text,
469→    extraction_confidence AS confidence,
470→    source_message AS sourceMessage,
471→    priority,
472→    created_at
473→  FROM task
474→  WHERE workspace = $workspace
475→    AND extraction_confidence != NONE
476→    AND id IN $project_entity_ids
477→    AND string::contains(string::lowercase(title), $query)
478→  ORDER BY created_at DESC
479→  LIMIT $safe_limit;
480→
481→  LET $decision_rows = SELECT
482→    id,
483→    "decision" AS kind,
484→    summary AS text,
485→    extraction_confidence AS confidence,
486→    source_message AS sourceMessage,
487→    priority,
488→    created_at
489→  FROM decision
490→  WHERE workspace = $workspace
491→    AND extraction_confidence != NONE
492→    AND id IN $project_entity_ids
493→    AND string::contains(string::lowercase(summary), $query)
494→  ORDER BY created_at DESC
495→  LIMIT $safe_limit;
496→
497→  LET $question_rows = SELECT
498→    id,
499→    "question" AS kind,
500→    text AS text,
501→    extraction_confidence AS confidence,
502→    source_message AS sourceMessage,
503→    priority,
504→    created_at
505→  FROM question
506→  WHERE workspace = $workspace
507→    AND extraction_confidence != NONE
508→    AND id IN $project_entity_ids
509→    AND string::contains(string::lowercase(text), $query)
510→  ORDER BY created_at DESC
511→  LIMIT $safe_limit;
512→
513→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
514→};
515→
516→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
517→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
518→  RETURN SELECT id, role, text, createdAt
519→  FROM message
520→  WHERE conversation = $conversation
521→  ORDER BY createdAt DESC
522→  LIMIT $safe_limit;
523→};
524→
525→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
526→  RETURN SELECT
527→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
528→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
529→  FROM $entity;
530→};
